const ASCII_CHARS = "@#S%?*+;:,. ";
const mapScale = (ASCII_CHARS.length - 1) / 255;

let imgCanvas, imgCtx;
let bitCanvas, bitCtx;

self.onmessage = async (e) => {
    const { 
      bitmap,
      width,
      height, 
      isColor,
      fontSize,
    } = e.data;
    
    if(!imgCanvas) {
        imgCanvas = new OffscreenCanvas(bitmap.width, bitmap.height);
        imgCtx = canvas.getContext("2d");
    }

    imgCanvas.width = bitmap.width;
    imgCanvas.height = bitmap.height;
    
    
    if (!bitCanvas) {
        bitCanvas = new OffscreenCanvas(width * fontSize, height * fontSize);
        bitCtx = bitCanvas.getContext("2d");
        bitCtx.textBaseline = "top";
    }

    bitCanvas.width = width * fontSize;
    bitCanvas.height = height * fontSize;

    
    bitCtx.clearRect(0, 0, bitCanvas.width, bitCanvas.height);
    bitCtx.font = `${fontSize}px monospace`;


    const srcW = bitmap.width;
    const srcH = bitmap.height;

    const dstW = width;
    const dstH = height;

    const srcAspect = srcW / srcH;
    const dstAspect = width / height;

    let dw, dh, offsetX, offsetY;

    if (srcAspect > dstAspect) {
        dw = width;
        dh = dw / srcAspect;
        offsetX = 0;
        offsetY = (height - dh) / 2;
    } else {
        dh = height;
        dw = dh * srcAspect;
        offsetY = 0;
        offsetX = (width - dw) / 2;
    }


    const scaleX = srcW / dstW;
    const scaleY = srcH / dstH;

    const imgData = imgCtx.getImageData(0, 0, srcW, srcH).data;

    let cell = 0;

    for (let y = 0; y < height; y++) {
        for (let x = 0; x < width; x++) {
            if (
                x < offsetX || x > offsetX + dw ||
                y < offsetY || y > offsetY + dh
            ) {
                continue;
            }

        const srcX = Math.floor((x - offsetX) * scaleX);
        const srcY = Math.floor((y - offsetY) * scaleY);

        const i = (srcY * srcW + srcX) * 4;

        const r = imgData[i];
        const g = imgData[i + 1];
        const b = imgData[i + 2];

        const brightness = (r + g + b) / 3 | 0;
        const char = ASCII_CHARS[brightness * mapScale | 0];

        bitCtx.fillStyle = isColor
        ? `rgb(${r}, ${g}, ${b})`
        : "fff";

        bitCtx.fillText(
            char,
            x * fontSize,
            y * fontSize
        );
      }
    }

    const result = bitCanvas.transferToImageBitmap();
    self.postMessage(result, [result]);
};
